\usepackage{xeCJK}
\usepackage{microtype}
\usepackage{hyperref}
\usepackage{cleveref}
\usepackage{geometry}
\usepackage{graphicx}
\usepackage{tikz}
\usetikzlibrary{arrows,positioning}
\geometry{margin=1in}

