\newtheorem{Theorem}{定理}[chapter]
\newtheorem{Lemma}{引理}[chapter]
\newtheorem{Corollary}{推论}[chapter]
\newtheorem{Proposition}{命题}[chapter]
\newtheorem{Example}{例}[chapter]
\newtheorem{Remark}{注}[chapter]
\newtheorem{Exercise}{练习}[chapter]

% User annotation command
\newcommand{\userannotation}[2]{%
  \begin{Remark}
    \textbf{#1:} #2
  \end{Remark}
}

% Information Geometry notation
\newcommand{\KL}[2]{D_{\mathrm{KL}}(#1 \| #2)}
\DeclareMathOperator{\Exp}{Exp}
\DeclareMathOperator{\KLdiv}{KL}
\DeclareMathOperator{\Fisher}{Fisher}

\title{信息几何讲义}
\author{Shun-ichi Amari et al.}
\date{\today}

\begin{document}

\maketitle

\tableofcontents

\include{chapters/chapter0}

\end{document}

