\chapter*{引言：文献概述}\label{chap:introduction}
\addcontentsline{toc}{chapter}{引言：文献概述}

本学习资料旨在系统研究信息几何（Information Geometry）领域。信息几何是利用微分几何方法研究概率分布空间的几何结构的学科，为统计学、机器学习、热力学和量子力学等领域提供了统一的数学框架。

\section{总述}

信息几何的核心思想是将概率分布族视为一个黎曼流形，利用几何方法来研究统计推断问题。这种观点起源于 Fisher 信息的研究，后来由 Rao、Cox、Amari 等学者发展为系统的几何理论。

本学习资料涵盖 24 篇文献，包括：
\begin{itemize}
    \item 核心教材：Amari 的经典著作、Ay 等人的数学基础
    \item 非参数信息几何：Pistone 开创性工作
    \item Orlicz 空间理论：处理非参数情况的重要工具
    \item 应用方向：进化博弈、热力学、量子信息等
\end{itemize}

\section{文献摘要总结}\label{sec:literature-summary}

本节按主题分类概述所有文献。

\subsection{一、核心教材}

\begin{enumerate}
    \item \textbf{作者:} Shun-ichi Amari
    \item \textbf{链接:} \url{https://link.springer.com/book/978-4-431-55978-8}
    \item \textbf{年份:} 2016
    \item \textbf{篇幅:} 376页
    \item \textbf{核心贡献:}
        \begin{itemize}
            \item 建立信息几何的完整理论框架
            \item 提出 $\alpha$-联络族理论
            \item 发展自然梯度下降在神经网络中的应用
            \item 系统阐述指数族与混合族的几何结构
        \end{itemize}
    \item \textbf{摘要:} 这是信息几何领域的奠基之作，由该领域创始人编写。内容涵盖概率分布空间的几何结构、Fisher 信息与 Cramér-Rao 下界、对偶平坦结构、统计学习中的几何方法等。
    \item \textbf{关键词:} Information Geometry；Fisher Information；$\alpha$-Connections；Exponential Family；Natural Gradient
\end{enumerate}

\begin{enumerate}
    \item \textbf{作者:} Nihat Ay, Jürgen Jost, Hông Vân Lê, Lorenz Schwachhofer
    \item \textbf{链接:} \url{https://link.springer.com/book/978-3-319-56478-4}
    \item \textbf{年份:} 2017
    \item \textbf{篇幅:} 300页
    \item \textbf{核心贡献:}
        \begin{itemize}
            \item 提供信息几何的严格数学基础
            \item 研究非参数统计流形的几何结构
            \item 探讨函数空间几何在信息几何中的应用
        \end{itemize}
    \item \textbf{摘要:} 侧重于信息几何的数学基础，是该领域重要的理论参考文献。
    \item \textbf{关键词:} Information Geometry；Statistical Manifold；Differential Geometry；Nonparametric
\end{enumerate}

\begin{enumerate}
    \item \textbf{作者:} Thomas M. Cover, Joy A. Thomas
    \item \textbf{链接:} \url{https://onlinelibrary.wiley.com/book/10.1002/047174882X}
    \item \textbf{年份:} 2006 (第二版)
    \item \textbf{篇幅:} 748页
    \item \textbf{核心贡献:}
        \begin{itemize}
            \item 建立信息论的完整理论体系
            \item 系统阐述熵、KL 散度、互信息等核心概念
            \item 为信息几何提供坚实的信息论基础
        \end{itemize}
    \item \textbf{摘要:} 信息论经典教材（GTM 134），为理解信息几何中的 KL 散度等概念提供背景知识。
    \item \textbf{关键词:} Information Theory；Entropy；KL Divergence；Mutual Information
\end{enumerate}
\end{enumerate}

\subsection{二、非参数信息几何}

\begin{enumerate}
    \item \textbf{作者:} Giovanni Pistone
    \item \textbf{链接:} \url{https://arxiv.org/abs/1306.0480}
    \item \textbf{年份:} 2013
    \item \textbf{篇幅:} 25页
    \item \textbf{核心贡献:}
        \begin{itemize}
            \item 开创非参数统计流形的微分几何结构研究
            \item 引入统计 bundle 概念
            \item 建立非参数情况下的几何理论框架
        \end{itemize}
    \item \textbf{摘要:} 本文研究了给定测度空间上正密度集合的微分几何结构，奠定了非参数信息几何的基础。
    \item \textbf{关键词:} Nonparametric Information Geometry；Statistical Bundle；Exponential Orlicz Space
\end{enumerate}

\begin{enumerate}
    \item \textbf{作者:} Giovanni Pistone
    \item \textbf{链接:} \url{https://arxiv.org/abs/2012.03376}
    \item \textbf{年份:} 2020
    \item \textbf{篇幅:} 18页
    \item \textbf{核心贡献:}
        \begin{itemize}
            \item 介绍 Orlicz 空间在信息几何中的应用
            \item 涵盖指数 Orlicz 空间和 Gaussian Orlicz-Sobolev 空间
            \item 是 2020 年 Les Houches 暑期学校讲义
        \end{itemize}
    \item \textbf{摘要:} 本教程介绍了 Orlicz 空间在非参数信息几何中的应用，包括统计 bundle、指数 Orlicz 空间等概念。
    \item \textbf{关键词:} Orlicz Spaces；Information Geometry；Nonparametric
\end{enumerate}

\begin{enumerate}
    \item \textbf{作者:} Paolo Gibilisco, Giovanni Pistone
    \item \textbf{链接:} \url{https://arxiv.org/abs/math/9801015}
    \item \textbf{年份:} 1998
    \item \textbf{篇幅:} 23页
    \item \textbf{核心贡献:}
        \begin{itemize}
            \item 利用 Orlicz 空间几何研究非参数统计流形上的联络
