    \item \textbf{篇幅:} 300页
    \item \textbf{核心贡献:}
        \begin{itemize}
            \item 提供信息几何的严格数学基础
            \item 研究非参数统计流形的几何结构
            \item 探讨函数空间几何在信息几何中的应用
        \end{itemize}
    \item \textbf{摘要:} 侧重于信息几何的数学基础，是该领域重要的理论参考文献。
    \item \textbf{关键词:} Information Geometry；Statistical Manifold；Differential Geometry；Nonparametric
\end{enumerate}

\subsubsection{\textbf{\textit{Elements of Information Theory}} — Cover \& Thomas}
\begin{enumerate}
    \item \textbf{作者:} Thomas M. Cover, Joy A. Thomas
    \item \textbf{链接:} \url{https://onlinelibrary.wiley.com/book/10.1002/047174882X}
    \item \textbf{年份:} 2006 (第二版)
    \item \textbf{篇幅:} 748页
    \item \textbf{核心贡献:}
        \begin{itemize}
            \item 建立信息论的完整理论体系
